// Extract text from either audio transcription or text message
let orderText = '';
let customerPhone = '';
let customerName = '';

if ($input.item.json.body.message.type === 'audio') {
  orderText = $input.item.json.text || '';
} else {
  orderText = $input.item.json.body.message.text.body || '';
}

customerPhone = $input.item.json.body.message.from || '';
customerName = $input.item.json.body.contact?.name || 'Unknown Customer';

return {
  json: {
    orderText: orderText,
    customerPhone: customerPhone,
    customerName: customerName,
    timestamp: new Date().toISOString(),
    rawMessage: $input.item.json
  }
};

// Parse the AI response and extract product list
let products = [];

try {
  const aiResponse = $input.item.json.text || $input.item.json.choices[0].message.content;

  // Try to extract JSON from response
  const jsonMatch = aiResponse.match(/\[.*\]/s);
  if (jsonMatch) {
    products = JSON.parse(jsonMatch[0]);
  }
} catch (error) {
  console.error('Error parsing AI response:', error);
  products = [];
}

return {
  json: {
    ...($input.item.json),
    parsedProducts: products,
    productCount: products.length
  }
};

// Match ordered products with database and calculate prices
const orderedProducts = $input.first().json.parsedProducts || [];
const dbProducts = $input.last().json.values || [];

// Create product lookup map (assuming columns: Product Name, Price, Stock)
const productMap = {};
for (let i = 1; i < dbProducts.length; i++) {
  const [name, price, stock] = dbProducts[i];
  if (name) {
    productMap[name.toLowerCase().trim()] = {
      name: name,
      price: parseFloat(price) || 0,
      stock: parseInt(stock) || 0
    };
  }
}

let validItems = [];
let invalidItems = [];
let totalAmount = 0;

for (const item of orderedProducts) {
  const productKey = item.product.toLowerCase().trim();
  const quantity = parseInt(item.quantity) || 1;

  if (productMap[productKey]) {
    const dbProduct = productMap[productKey];

    if (dbProduct.stock >= quantity) {
      const itemTotal = dbProduct.price * quantity;
      validItems.push({
        product: dbProduct.name,
        quantity: quantity,
        unitPrice: dbProduct.price,
        totalPrice: itemTotal,
        available: true
      });
      totalAmount += itemTotal;
    } else {
      invalidItems.push({
        product: item.product,
        quantity: quantity,
        reason: `Insufficient stock (Available: ${dbProduct.stock})`
      });
    }
  } else {
    invalidItems.push({
      product: item.product,
      quantity: quantity,
      reason: 'Product not found in database'
    });
  }
}

return {
  json: {
    customerPhone: $input.first().json.customerPhone,
    customerName: $input.first().json.customerName,
    timestamp: $input.first().json.timestamp,
    validItems: validItems,
    invalidItems: invalidItems,
    totalAmount: totalAmount,
    orderStatus: validItems.length > 0 ? 'partial_success' : 'failed',
    validItemCount: validItems.length,
    invalidItemCount: invalidItems.length
  }
};

// Prepare order data for Google Sheets
const order = $input.item.json;

const rows = [];

for (const item of order.validItems) {
  rows.push({
    json: {
      values: [
        order.timestamp,
        order.customerName,
        order.customerPhone,
        item.product,
        item.quantity,
        item.unitPrice,
        item.totalPrice,
        order.orderStatus
      ]
    }
  });
}

return rows;

