// Generate confirmation message
const order = $input.item.json;

let message = `✅ Order Confirmed!\n\n`;
message += `Dear ${order.customerName},\n\n`;
message += `Thank you for your order!\n\n`;
message += `**Order Summary:**\n`;

for (const item of order.validItems) {
  message += `• ${item.product} x ${item.quantity} = $${item.totalPrice.toFixed(2)}\n`;
}

message += `\n**Total: $${order.totalAmount.toFixed(2)}**\n\n`;

if (order.invalidItems.length > 0) {
  message += `⚠️ **Some items were unavailable:**\n`;
  for (const item of order.invalidItems) {
    message += `• ${item.product} - ${item.reason}\n`;
  }
  message += `\n`;
}

message += `Your order has been received and will be processed shortly.\n\n`;
message += `Order ID: ${Date.now()}\n`;
message += `Date: ${new Date(order.timestamp).toLocaleString()}`;

return {
  json: {
    ...order,
    confirmationMessage: message
  }
};
